'use strict';
(function(){
localStorage.removeItem('nt_usability_test');
sessionStorage.removeItem('nt_usability_test');
if(!new URLSearchParams(window.location.search).has('test'))return;
var FORM_URL='https://docs.google.com/forms/d/e/1FAIpQLSf2uFI6NakVZfKmFPy2iFqEoeV0cBY-3VwPFT61o7qIYsmcOQ/viewform?usp=dialog';
var formWindow=null;
var btn=document.createElement('button');
btn.textContent='Open Test Form';
Object.assign(btn.style,{
position:'fixed',
bottom:'20px',
right:'20px',
zIndex:'999999',
padding:'12px 24px',
background:'#4a7c59',
color:'#fff',
border:'none',
borderRadius:'8px',
fontSize:'15px',
fontWeight:'600',
fontFamily:'system-ui, -apple-system, sans-serif',
cursor:'pointer',
boxShadow:'0 4px 12px rgba(0,0,0,0.3)'});
btn.addEventListener('click',function(){
if(formWindow&&!formWindow.closed){
formWindow.focus();
return;}
var width=520;
var height=window.screen.availHeight;
var left=window.screen.availWidth-width;
formWindow=window.open(
FORM_URL,'nt_test_form','width='+width+',height='+height+',left='+left+',top=0,resizable=yes,scrollbars=yes');});
document.body.appendChild(btn);})();